INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility, participant_structure,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility', 'pairs',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Partner Trunk Twist Med Ball Exchange', 'partner-trunk-twist-med-ball-exchange', 'Partners stand back-to-back or side-by-side and exchange a medicine ball through controlled trunk rotation.', 'BEGINNER', 8, 2, 5, NULL, 35, 80, 'Partner Trunk Twist Med Ball Exchange is a two-person paired exercise for timed trunk rotation, posture, and coordinated handoff under a shared rhythm. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.', 'Primary subrole: perception_action_skill. Coach Partner Trunk Twist Med Ball Exchange as pair-specific work: define roles, cap partner force, use clear stop commands, and preserve quality before competition.', 'Communicate, match your partner, and own the reset.', 'Rotational trunk exchange', 'movement_intelligence', 'perception_action_skill', 'partner_trunk_twist_med_ball_exchange', '{"primary_joint_actions":["trunk rotation","hip rotation","weight shift"],"primary_tissues":["core","spine","hip"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"high","impact_level":0,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"reactive_output_profile":{"stimulus_type":"partner visual, tactile, or ball cue","amplitude_cap":"short, safe, and repeatable","quality_rule":"stop before timing, speed, catch quality, or decision quality degrades"}}'::jsonb, '{"movement_description":"Partners stand back-to-back or side-by-side and exchange a medicine ball through controlled trunk rotation.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: Partners stand back-to-back or side-by-side and exchange a medicine ball through controlled trunk rotation.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input"]}'::jsonb),
  ('Partner Sit-Up Medicine Ball Throw', 'partner-sit-up-medicine-ball-throw', 'One athlete performs a controlled sit-up and throws the medicine ball to a standing or kneeling partner, then receives it back.', 'BEGINNER', 8, 2, NULL, 20, 40, 80, 'Partner Sit-Up Medicine Ball Throw is a two-person paired exercise for anterior trunk control, breathing under effort, and coordinated throw-catch timing. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.', 'Primary subrole: trunk_pelvis_anti_movement_control. Coach Partner Sit-Up Medicine Ball Throw as pair-specific work: define roles, cap partner force, use clear stop commands, and preserve quality before competition.', 'Communicate, match your partner, and own the reset.', 'Supine trunk throw', 'resilience', 'trunk_pelvis_anti_movement_control', 'partner_sit_up_med_ball_throw', '{"primary_joint_actions":["trunk anti-movement","hip stability","breathing under tension"],"primary_tissues":["core","spine","hip"],"breathing_demand":"moderate","balance_demand":"high","coordination_demand":"moderate","impact_level":0,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"anti_movement_profile":{"external_force_source":"partner","force_rule":"predictable, progressive, and agreed before the rep","rotation_tolerance":"minimal trunk or pelvis leak before reset"}}'::jsonb, '{"movement_description":"One athlete performs a controlled sit-up and throws the medicine ball to a standing or kneeling partner, then receives it back.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: One athlete performs a controlled sit-up and throws the medicine ball to a standing or kneeling partner, then receives it back.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input","Perturbation becomes a challenge contest instead of controlled exposure"]}'::jsonb),
  ('Partner Medicine Ball Shot-Put Pass', 'partner-medicine-ball-shot-put-pass', 'Athlete uses a staggered stance and one-arm shot-put style pass to a partner, alternating sides.', 'INTERMEDIATE', 8, 3, 4, NULL, 60, 120, 'Partner Medicine Ball Shot-Put Pass is a two-person paired exercise for single-arm horizontal power, trunk rotation, and front-leg bracing. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.', 'Primary subrole: jump_throw_explosive_power. Coach Partner Medicine Ball Shot-Put Pass as pair-specific work: define roles, cap partner force, use clear stop commands, and preserve quality before competition.', 'Communicate, match your partner, and own the reset.', 'Single-arm throw power', 'output', 'jump_throw_explosive_power', 'partner_med_ball_shot_put_pass', '{"primary_joint_actions":["shoulder horizontal press","elbow extension","trunk bracing"],"primary_tissues":["shoulder","core","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"high","impact_level":1,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"reactive_output_profile":{"stimulus_type":"partner visual, tactile, or ball cue","amplitude_cap":"short, safe, and repeatable","quality_rule":"stop before timing, speed, catch quality, or decision quality degrades"}}'::jsonb, '{"movement_description":"Athlete uses a staggered stance and one-arm shot-put style pass to a partner, alternating sides.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: Athlete uses a staggered stance and one-arm shot-put style pass to a partner, alternating sides.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input","Reps continue after speed or decision quality drops"]}'::jsonb),
  ('Partner Lateral Shuffle Med Ball Pass', 'partner-lateral-shuffle-med-ball-pass', 'Partners shuffle laterally in parallel lanes while exchanging controlled chest or scoop passes.', 'INTERMEDIATE', 8, 2, 5, NULL, 35, 80, 'Partner Lateral Shuffle Med Ball Pass is a two-person paired exercise for throw accuracy while moving, lateral footwork rhythm, and catch posture. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.', 'Primary subrole: perception_action_skill. Coach Partner Lateral Shuffle Med Ball Pass as pair-specific work: define roles, cap partner force, use clear stop commands, and preserve quality before competition.', 'Communicate, match your partner, and own the reset.', 'Throw plus lateral footwork', 'movement_intelligence', 'perception_action_skill', 'partner_lateral_shuffle_med_ball_pass', '{"primary_joint_actions":["hip flexion-extension","ankle stiffness","direction change"],"primary_tissues":["foot","ankle","knee"],"breathing_demand":"low_to_moderate","balance_demand":"high","coordination_demand":"high","impact_level":1,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"reactive_output_profile":{"stimulus_type":"partner visual, tactile, or ball cue","amplitude_cap":"short, safe, and repeatable","quality_rule":"stop before timing, speed, catch quality, or decision quality degrades"}}'::jsonb, '{"movement_description":"Partners shuffle laterally in parallel lanes while exchanging controlled chest or scoop passes.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: Partners shuffle laterally in parallel lanes while exchanging controlled chest or scoop passes.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input"]}'::jsonb),
