  ('partner-wheelbarrow-walk', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('partner-buddy-carry', FALSE, 2, 48, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('partner-pallof-band-hold', FALSE, 4, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('partner-plank-hand-tap', FALSE, 4, 12, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('partner-dead-bug-hand-press', TRUE, 5, 0, FALSE, FALSE, FALSE, FALSE, FALSE),
  ('partner-hollow-body-med-ball-exchange', FALSE, 4, 12, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('partner-single-leg-balance-ball-toss', FALSE, 4, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('partner-chase-sprint-start', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('partner-tennis-ball-drop-sprint', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
