  ('partner-45-degree-cut-callout-chase', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('partner-shadow-defense-drill', FALSE, 4, 12, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('partner-backpedal-turn-and-go-cue', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
