  ('partner-hand-fighting-footwork', FALSE, 4, 12, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('partner-pummeling-balance-drill', FALSE, 4, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
