-- Pairs exercise cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'pairs_exercise_readiness',
  NULL,
  'Pairs exercise library without group chaos or conditioning drift',
  'Paired drills require exactly two people with defined roles, capped partner force, and quality gates — not random partner contests, fatigue games, or group drills mislabeled as pairs work.',
  'The Top 50 Pairs library spans partner med-ball throws, manual resistance, perturbation control, reactive agility mirrors, and cooperative locomotion across Output, Movement Intelligence, Resilience, Capacity, and Prepare & Access.',
  'A live partner creates timing, resistance, and perception constraints solo drills cannot replicate. Poor role definition, surprise force, or extended sets after quality drops raise injury risk and train sloppy communication.',
  'Define athlete and partner roles before the first rep. Dose both roles; switch before fatigue changes behavior. Keep Output and reactive work fresh with full rest. Stop when speed, spacing, catch quality, or communication breaks.',
  'Do not let partners add random force, chase competition over quality, or extend reps until breathing decides the outcome. Do not use pairs drills that require three or more people or hide conditioning as speed work.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
